let passed = 0;
let failed = 0;

function assert(condition, msg) {
  if (condition) { passed++; console.log('  ✅', msg); }
  else { failed++; console.error('  ❌', msg); }
}

// Test extractTokens
console.log('\n--- extractTokens ---');
assert(extractTokens('').length === 0, 'empty string → []');
assert(extractTokens(null).length === 0, 'null → []');
const t1 = extractTokens('how to build code text');
assert(t1.includes('build') && t1.includes('code'), 'multi-token: includes \"build\" and \"code\"');
assert(!t1.includes('to'), 'multi-token: filters stopword \"to\"');

