const r3 = [{ score: 0.4, symbolNames: [] }];
applySymbolBoost(r3, 'buildCodeText');
assert(Math.abs(r3[0].score - 0.4) < 0.001, 'empty array → no boost');

// Test applySymbolBoost - undefined symbolNames
const r4 = [{ score: 0.7 }];
applySymbolBoost(r4, 'buildCodeText');
assert(Math.abs(r4[0].score - 0.7) < 0.001, 'missing field → no boost');

