// Test applySymbolBoost - null results
const result = applySymbolBoost(null, 'test');
assert(result === null, 'null results → returns null');

console.log('\n--- Results: ' + passed + ' passed, ' + failed + ' failed ---');
process.exit(failed > 0 ? 1 : 0);
